ontemDate.setDate(ontemDate.getDate() - 1);
const dataOntem = ontemDate.toISOString().split('T')[0];
const inicioMes = hojeStr.substring(0, 7) + '-01';
const mesAtual = hojeDate.getMonth();
const monthRef = hojeStr.substring(0, 7);
const supabaseUrl = 'https://tyrxbarucopizpcalooh.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InR5cnhiYXJ1Y29waXpwY2Fsb29oIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NTIwMDQ0OTUsImV4cCI6MjA2NzU4MDQ5NX0.ycJzhslzMyD0DQWWu5hY09SucH94OTwWI60oIqm-EB8';
const headers = { 'apikey': supabaseKey, 'Authorization': 'Bearer ' + supabaseKey };
const ORCAMENTO = [
  { month: 0, producao: 17118.27, energia: 80.76, gas: 45.40 },
  { month: 1, producao: 20400, energia: 75.00, gas: 41.95 },
  { month: 2, producao: 23000, energia: 75.00, gas: 41.83 },
  { month: 3, producao: 21800, energia: 75.00, gas: 42.08 },
  { month: 4, producao: 22300, energia: 75.00, gas: 41.83 },
  { month: 5, producao: 11200, energia: 75.00, gas: 41.50 },
  { month: 6, producao: 11400, energia: 75.00, gas: 42.43 },
  { month: 7, producao: 22500, energia: 75.00, gas: 41.00 },
  { month: 8, producao: 21500, energia: 75.00, gas: 40.00 },
  { month: 9, producao: 22000, energia: 75.00, gas: 39.00 },
  { month: 10, producao: 21300, energia: 73.00, gas: 38.00 },
  { month: 11, producao: 22000, energia: 72.00, gas: 38.00 }
];
const budgetMes = ORCAMENTO.find(b => b.month === mesAtual) || ORCAMENTO[1];
let historicoMes = [];
let justificativas = [];
try {
  const [hResp, jResp] = await Promise.all([
    this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/diario_bordo_real?data=gte.' + inicioMes + '&data=lte.' + dataOntem + '&order=data.asc', headers }),
    this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/kpi_justifications?month_ref=eq.' + monthRef, headers })
  ]);
  historicoMes = Array.isArray(hResp) ? hResp : [];
  justificativas = Array.isArray(jResp) ? jResp : [];
} catch(e) {
  historicoMes = $('Get Forecast Ontem').all().map(i => i.json);
}
const recOntem = historicoMes.find(r => r.data === dataOntem) || historicoMes[historicoMes.length - 1] || {};
const justMap = {};
justificativas.forEach(j => { justMap[j.kpi_type] = j.justification; });
const acumProd = historicoMes.reduce((s, r) => s + (parseFloat(r.producao_laminacao) || 0), 0);
const acumGasRaw = historicoMes.reduce((s, r) => s + (parseFloat(r.consumo_gas_tl01) || 0), 0);
const acumEe = historicoMes.reduce((s, r) => s + (parseFloat(r.consumo_energia_total) || 0), 0);
let totalFatorPCS = 0, countFatorPCS = 0;
historicoMes.forEach(r => { const f = parseFloat(r.fator_pcs); if (!isNaN(f) && f > 0) { totalFatorPCS += f; countFatorPCS++; } });
const fatorPCS = countFatorPCS > 0 ? totalFatorPCS / countFatorPCS : 1;
const acumGas = acumGasRaw * fatorPCS;
const prodDia = parseFloat(recOntem.producao_laminacao) || 0;
const gasDia = (parseFloat(recOntem.consumo_gas_tl01) || 0) * fatorPCS;
const eeDia = parseFloat(recOntem.consumo_energia_total) || 0;
const gasEspecDia = prodDia > 0 ? gasDia / prodDia : 0;
const eeEspecDia = prodDia > 0 ? eeDia / prodDia : 0;
const gasEspecAcum = acumProd > 0 ? acumGas / acumProd : 0;
const eeEspecAcum = acumProd > 0 ? acumEe / acumProd : 0;

// PREVISAO: FONTE UNICA = tabela forecast_cache no Supabase
let previsaoProducao = 0;
let forecastDebug = 'buscando forecast_cache';
try {
  const cacheResp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/forecast_cache?id=eq.current&select=previsao_fechamento,previsao_gas,previsao_energia,updated_at',
    headers
  });
  if (Array.isArray(cacheResp) && cacheResp.length > 0 && cacheResp[0].previsao_fechamento > 0) {
    previsaoProducao = Math.round(cacheResp[0].previsao_fechamento);
    previsaoGnEspec = cacheResp[0].previsao_gas || 0;
    previsaoEeEspec = cacheResp[0].previsao_energia || 0;
    forecastDebug = 'forecast_cache OK: ' + previsaoProducao + ' (at ' + cacheResp[0].updated_at + ')';
  }
} catch(e) {
  forecastDebug = 'forecast_cache FALHOU: ' + (e.message || '').substring(0, 60);
}
if (previsaoProducao === 0) {
  try {
    const forecastResp = await this.helpers.httpRequest({ method: 'GET', url: 'http://127.0.0.1:3000/api/forecast', timeout: 3000 });
    if (forecastResp && forecastResp.previsaoFechamento > 0) {
      previsaoProducao = forecastResp.previsaoFechamento;
      previsaoGnEspec = forecastResp.previsaoGas || 0;
      previsaoEeEspec = forecastResp.previsaoEnergia || 0;
      forecastDebug += ' | API local OK: ' + previsaoProducao;
    }
  } catch(e) { forecastDebug += ' | API local falhou'; }
}
if (previsaoProducao === 0) {
  try {
    const fimMesStr2 = new Date(hojeDate.getFullYear(), mesAtual + 1, 1).toISOString().split('T')[0];
    const pcpResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/pcp_data?select=producao_planejada&inicio=gte.' + inicioMes + 'T00:00:00&inicio=lt.' + fimMesStr2 + 'T00:00:00', headers });
    const pcpAll = Array.isArray(pcpResp) ? pcpResp : [];
    const soma = pcpAll.reduce((s, r) => s + (parseFloat(r.producao_planejada) || 0), 0);
    if (soma > 0) { previsaoProducao = Math.round(soma); forecastDebug += ' | PCP soma: ' + previsaoProducao; }
  } catch(e2) { forecastDebug += ' | PCP falhou'; }
}
if (previsaoProducao === 0) {
  const diaRef = hojeDate.getDate() - 1;
  const totalDias = new Date(hojeDate.getFullYear(), hojeDate.getMonth() + 1, 0).getDate();
  previsaoProducao = diaRef > 0 ? Math.round((acumProd / diaRef) * totalDias) : Math.round(acumProd);
  forecastDebug += ' | Linear: ' + previsaoProducao;
}

if (previsaoGnEspec === 0) previsaoGnEspec = gasEspecAcum;
if (previsaoEeEspec === 0) previsaoEeEspec = eeEspecAcum;
let previsaoGnEspec = 0;
let previsaoEeEspec = 0;
const fimMesStr = new Date(hojeDate.getFullYear(), mesAtual + 1, 1).toISOString().split('T')[0];
let pcpMes = [];
try {
  const pcpFamResp = await this.helpers.httpRequest({ method: 'GET', url: supabaseUrl + '/rest/v1/pcp_data?select=familia,inicio&and=(inicio.gte.' + inicioMes + 'T00:00:00,inicio.lt.' + fimMesStr + 'T00:00:00)&order=inicio.asc&limit=500', headers });
  pcpMes = Array.isArray(pcpFamResp) ? pcpFamResp : [];
} catch(e) {}
function simplificarFamilia(fam) {
  const f = (fam || '').toUpperCase().trim();
  if (f.includes('CHATO MOLA')) return 'Barra Chata Mola';
  if (f.includes('CHATO')) return 'Barra Chata';
  if (f.includes('CANTONEIRA')) return 'Cantoneira';
  if (f.includes('REDONDA')) return 'Barra Redonda';
  if (f.includes('VIGA I')) return 'Viga I';
  if (f.includes('VIGA U')) return 'Viga U';
  if (f.includes('TRILHO')) return 'Trilho';
  if (f.includes('PERFIL')) return 'Perfil';
  return f || 'Outros';
}
const pcpDia = pcpMes.filter(p => (p.inicio || '').split('T')[0] === dataOntem);
const familiasTexto = [...new Set(pcpDia.map(p => simplificarFamilia(p.familia)).filter(f => f !== 'Outros'))].join(', ') || 'Nao identificado';
const dataFormatada = dataOntem.split('-').reverse().join('/');
const fmt = (n) => Number(n).toFixed(2).replace('.', ',');
const fmtInt = (n) => Math.round(Number(n)).toString();
const prompt = 'Crie um resumo diario em texto corrido, SEM asteriscos, SEM negrito, SEM emojis, SEM markdown. Destinado a diretoria.\n\nREGRAS:\n1. Diga sempre dia anterior ou fechamento do dia. Nunca turno anterior.\n2. Nunca use T isolado. Escreva toneladas por extenso.\n3. Gas natural: metro cubico por tonelada.\n4. Energia eletrica: quilowatt-hora por tonelada.\n5. Seja direto. Se houver justificativa para um KPI, inclua naturalmente.\n6. INICIE COM:\n\nBom dia. Este e o nosso briefing diario com o balanco do fechamento do dia ' + dataFormatada + '.\n\nDados de producao:\nAcumulado do mes: ' + fmt(acumProd) + ' toneladas.\nProducao do dia anterior: ' + fmtInt(prodDia) + ' toneladas.\nPrevisao de fechamento do mes: ' + fmtInt(previsaoProducao) + ' toneladas (orcamento: ' + fmtInt(budgetMes.producao) + ' toneladas).\n' + (justMap.producao ? 'Nota: ' + justMap.producao : '') + '\n\nGas natural:\nConsumo especifico acumulado: ' + fmt(gasEspecAcum) + ' m3 por tonelada.\nConsumo especifico do dia anterior: ' + fmt(gasEspecDia) + ' m3 por tonelada.\nPrevisao de fechamento: ' + fmt(previsaoGnEspec) + ' m3 por tonelada.\n' + (justMap.gas ? 'Nota: ' + justMap.gas : '') + '\n\nEnergia eletrica:\nConsumo especifico acumulado: ' + fmt(eeEspecAcum) + ' kWh por tonelada.\nConsumo especifico do dia anterior: ' + fmt(eeEspecDia) + ' kWh por tonelada.\nPrevisao de fechamento: ' + fmt(previsaoEeEspec) + ' kWh por tonelada.\n' + (justMap.energia ? 'Nota: ' + justMap.energia : '') + '\n\nAgradeco a atencao. Sigamos focados.';
return [{ json: {
  prompt,
  dataRef: dataFormatada,
  dataISO: dataOntem,
  material: familiasTexto,
  producao: { acumulada: fmt(acumProd), dia: fmtInt(prodDia), previsao: fmtInt(previsaoProducao), orcamento: fmtInt(budgetMes.producao), justificativa: justMap.producao || '' },
  gn: { acumEspec: fmt(gasEspecAcum), especDia: fmt(gasEspecDia), previsao: fmt(previsaoGnEspec), fatorPCS: fatorPCS.toFixed(6), justificativa: justMap.gas || '' },
  ee: { acumEspec: fmt(eeEspecAcum), especDia: fmt(eeEspecDia), previsao: fmt(previsaoEeEspec), justificativa: justMap.energia || '' },
  debug: { hojeStr, dataOntem, diasHistorico: historicoMes.length, forecastAPI: forecastDebug }
} }];

const { execSync } = require('child_process');
const path = require('path');
const fs = require('fs');

const audioData = $input.first().json.candidates[0].content.parts[0].inlineData.data;
const pcmBuffer = Buffer.from(audioData, 'base64');

// Monta cabeçalho WAV (PCM 16-bit, 24000 Hz, Mono)
const sampleRate = 24000;
const numChannels = 1;
const bitsPerSample = 16;
const byteRate = sampleRate * numChannels * (bitsPerSample / 8);
const blockAlign = numChannels * (bitsPerSample / 8);
const dataSize = pcmBuffer.length;
const wavBuffer = Buffer.alloc(44 + dataSize);
wavBuffer.write('RIFF', 0);
wavBuffer.writeUInt32LE(36 + dataSize, 4);
wavBuffer.write('WAVE', 8);
wavBuffer.write('fmt ', 12);
wavBuffer.writeUInt32LE(16, 16);
wavBuffer.writeUInt16LE(1, 20);
wavBuffer.writeUInt16LE(numChannels, 22);
wavBuffer.writeUInt32LE(sampleRate, 24);
wavBuffer.writeUInt32LE(byteRate, 28);
wavBuffer.writeUInt16LE(blockAlign, 32);
wavBuffer.writeUInt16LE(bitsPerSample, 34);
wavBuffer.write('data', 36);
wavBuffer.writeUInt32LE(dataSize, 40);
pcmBuffer.copy(wavBuffer, 44);

const audioDir = 'C:\\Users\\40000398\\OneDrive - ArcelorMittal\\Desktop\\n8n\\public\\audio';
const wavPath = path.join(audioDir, 'daily_briefing.wav');
const mp3Path = path.join(audioDir, 'daily_briefing.mp3');

// Garante que o diretório existe
if (!fs.existsSync(audioDir)) fs.mkdirSync(audioDir, { recursive: true });

// Salva WAV (necessário como base para o MP3 ou fallback)
fs.writeFileSync(wavPath, wavBuffer);

// Converte para MP3 enviando para o site via API
try {
  const tempWav = path.join(audioDir, 'daily_briefing_temp.wav');
  fs.writeFileSync(tempWav, wavBuffer);
  execSync(`ffmpeg -y -i "${tempWav}" -codec:a libmp3lame -b:a 128k -ar 44100 "${mp3Path}"`, { timeout: 120000 });
  fs.unlinkSync(tempWav);

  const mp3Base64 = fs.readFileSync(mp3Path, 'base64');
  const briefingText = $('Extrair Texto do Briefing').first().json.briefingText || '';

  // Envia MP3 e Texto para a API do site
  const result = await this.helpers.httpRequest({ 
    method: 'POST', 
    url: 'http://127.0.0.1:3000/api/audio', 
    body: { 
      audioFilename: 'daily_briefing.mp3', 
      audioData: mp3Base64, 
      textFilename: 'daily_briefing.txt', 
      textContent: briefingText 
    }, 
    headers: { 'Content-Type': 'application/json' }, 
    timeout: 30000 
  });

  return [{ json: { status: 'Briefing MP3 gerado e enviado', mp3Path, ...result } }];
} catch(err) {
  // Se falhar o MP3, envia o WAV original
  const wavBase64 = wavBuffer.toString('base64');
  const briefingText = $('Extrair Texto do Briefing').first().json.briefingText || '';
  const result = await this.helpers.httpRequest({ 
    method: 'POST', 
    url: 'http://127.0.0.1:3000/api/audio', 
    body: { 
      audioFilename: 'daily_briefing.wav', 
      audioData: wavBase64, 
      textFilename: 'daily_briefing.txt', 
      textContent: briefingText 
    }, 
    headers: { 'Content-Type': 'application/json' }, 
    timeout: 30000 
  });
  return [{ json: { status: 'ffmpeg falhou, enviado como WAV', error: err.message, ...result } }];
